#!/bin/bash
set -euo pipefail

mkdir -p '\opt\tomcat\webapps\ROOT\WEB-INF\classes\com\robodynamics\controller'
cat <<'B64' | base64 -d > '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDStudentDashboardController.class'

B64
chown tomcat:tomcat '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDStudentDashboardController.class' || true
chmod 640 '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDStudentDashboardController.class' || true

mkdir -p '\opt\tomcat\webapps\ROOT\WEB-INF\classes\com\robodynamics\controller'
cat <<'B64' | base64 -d > '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDAITutorLaunchController.class'

B64
chown tomcat:tomcat '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDAITutorLaunchController.class' || true
chmod 640 '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDAITutorLaunchController.class' || true

mkdir -p '\opt\tomcat\webapps\ROOT\WEB-INF\classes\com\robodynamics\controller'
cat <<'B64' | base64 -d > '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDAITutorIntegrationController.class'

B64
chown tomcat:tomcat '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDAITutorIntegrationController.class' || true
chmod 640 '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDAITutorIntegrationController.class' || true

mkdir -p '\opt\tomcat\webapps\ROOT\WEB-INF\classes\com\robodynamics\service\impl'
cat <<'B64' | base64 -d > '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/service/impl/RDAITutorIntegrationService.class'

B64
chown tomcat:tomcat '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/service/impl/RDAITutorIntegrationService.class' || true
chmod 640 '/opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/service/impl/RDAITutorIntegrationService.class' || true

mkdir -p '\opt\tomcat\webapps\ROOT\WEB-INF\views'
cat <<'B64' | base64 -d > '/opt/tomcat/webapps/ROOT/WEB-INF/views/studentDashboard.jsp'

B64
chown tomcat:tomcat '/opt/tomcat/webapps/ROOT/WEB-INF/views/studentDashboard.jsp' || true
chmod 640 '/opt/tomcat/webapps/ROOT/WEB-INF/views/studentDashboard.jsp' || true

mkdir -p '\opt\tomcat\webapps\ROOT\WEB-INF\classes'
cat <<'B64' | base64 -d > '/opt/tomcat/webapps/ROOT/WEB-INF/classes/app-config.properties'

B64
chown tomcat:tomcat '/opt/tomcat/webapps/ROOT/WEB-INF/classes/app-config.properties' || true
chmod 640 '/opt/tomcat/webapps/ROOT/WEB-INF/classes/app-config.properties' || true

mkdir -p '\opt\robodynamics\ai-tutor\tutor-api\app'
cat <<'B64' | base64 -d > '/opt/robodynamics/ai-tutor/tutor-api/app/main.py'

B64
chown root:root '/opt/robodynamics/ai-tutor/tutor-api/app/main.py' || true
chmod 644 '/opt/robodynamics/ai-tutor/tutor-api/app/main.py' || true

mkdir -p '\opt\robodynamics\ai-tutor\tutor-api\app\services'
cat <<'B64' | base64 -d > '/opt/robodynamics/ai-tutor/tutor-api/app/services/engine_registry.py'

B64
chown root:root '/opt/robodynamics/ai-tutor/tutor-api/app/services/engine_registry.py' || true
chmod 644 '/opt/robodynamics/ai-tutor/tutor-api/app/services/engine_registry.py' || true

mkdir -p '\opt\robodynamics\ai-tutor\web\app\ai-tutor\vedic'
cat <<'B64' | base64 -d > '/opt/robodynamics/ai-tutor/web/app/ai-tutor/vedic/page.tsx'

B64
chown root:root '/opt/robodynamics/ai-tutor/web/app/ai-tutor/vedic/page.tsx' || true
chmod 644 '/opt/robodynamics/ai-tutor/web/app/ai-tutor/vedic/page.tsx' || true

if systemctl list-unit-files | awk '{print $1}' | grep -q '^tomcat9\.service$'; then TOMSVC=tomcat9; else TOMSVC=tomcat; fi
systemctl restart "$TOMSVC"
echo "TOMCAT=$(systemctl is-active $TOMSVC)"
cd /opt/robodynamics/ai-tutor/web
npm run build >/tmp/rd_ai_tutor_web_build.log 2>&1 || (tail -n 120 /tmp/rd_ai_tutor_web_build.log; exit 1)
systemctl restart rd-ai-tutor-api
systemctl restart rd-ai-tutor-web
echo "API=$(systemctl is-active rd-ai-tutor-api)"
echo "WEB=$(systemctl is-active rd-ai-tutor-web)"
stat -c 'JSP=%n SIZE=%s MTIME=%y' /opt/tomcat/webapps/ROOT/WEB-INF/views/studentDashboard.jsp
stat -c 'CLS=%n SIZE=%s MTIME=%y' /opt/tomcat/webapps/ROOT/WEB-INF/classes/com/robodynamics/controller/RDStudentDashboardController.class
stat -c 'PY=%n SIZE=%s MTIME=%y' /opt/robodynamics/ai-tutor/tutor-api/app/main.py
stat -c 'TSX=%n SIZE=%s MTIME=%y' /opt/robodynamics/ai-tutor/web/app/ai-tutor/vedic/page.tsx
